@startuml
title BADEXAMPLE's Class Diagram

package "solid" as solid {
  package "interfacesegregation" as interfacesegregation {
    package "badexample" as badexample {
      class AContainer {
        +AContainer()
        +doYourContainerStuffToMe()
      }
      class AMachine {
        +AMachine()
        +doSomeWork()
      }
      class MUser {
        +MUser()
        +doYourOperations()
      }
      class Operations {
        +operation1()
        +operation2()
        +operation3()
      }
    }
  }
}

AContainer ..> Operations : ops
AMachine ..> Operations : ops
MUser ..> Operations : ops

@enduml
